template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernelWithConflicts(T* in, T* out, int64_t num_blocks)
{
  __shared__ T temp[N];

  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  int thid = threadIdx.x;
  int offset = 1;

  temp[2*thid]   = t_in[2*thid];
  temp[2*thid+1] = t_in[2*thid+1];

  for (int d = N >> 1; d > 0; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1] = 0; 
  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }
  t_out[2*thid] = temp[2*thid];
  t_out[2*thid+1] = temp[2*thid+1];
}

template<typename T, int N>
__global__ void scanKernelWithoutConflicts(T* in, T* out, int64_t num_blocks)
{
  __shared__ T temp[2*N];

  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  int thid = threadIdx.x;
  int a = thid;
  int b = a + (N/2);
  int oa = OFFSET(a);
  int ob = OFFSET(b);

  temp[a + oa] = t_in[a];
  temp[b + ob] = t_in[b];

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1+OFFSET(N-1)] = 0; 
  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }
  __syncthreads();

  t_out[a] = temp[a + oa];
  t_out[b] = temp[b + ob];
}

template<typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;

  int64_t nelems = num_blocks * N; 

  int64_t bytes = nelems * sizeof(T);

  T *in_host = (T*) malloc (bytes);
  T *out_host = (T*) malloc (bytes);
  T *ref_out_host = (T*) malloc (bytes);

  T *in_dev = nullptr;
  T *out_dev = nullptr;

  cudaMalloc(&in_dev, bytes);
  cudaMalloc(&out_dev, bytes);

  srand(123);
  for (int64_t n = 0; n < nelems; n++) in_host[n] = rand() % 5 + 1;

  cudaMemcpy(in_dev, in_host, bytes, cudaMemcpyHostToDevice);

  T *t_in = in_host;
  T *t_out = ref_out_host;
  for (int64_t n = 0; n < num_blocks; n++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  dim3 block(N/2);
  dim3 grid(num_blocks);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scanKernelWithConflicts<T, N>(grid, block)(in_dev, out_dev, num_blocks);
  }

  cudaDeviceSynchronize();
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }
  cudaMemcpy(out_host, out_dev, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out_host, out_host, nelems);


  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scanKernelWithoutConflicts<T, N>(grid, block)(in_dev, out_dev, num_blocks);
  }

  cudaDeviceSynchronize();
  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  cudaMemcpy(out_host, out_dev, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out_host, out_host, nelems);

  cudaFree(in_dev);
  cudaFree(out_dev);
  free(in_host);
  free(out_host);
  free(ref_out_host);
}

template<int N>
void run (const int n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
