__global__ void process_block_kernel(int* a, int* b, int length, int pad_size, int block_start) {
    int j = threadIdx.x;
    if (j < BLOCK_SIZE) {
        int temp[BLOCK_SIZE + 2 * RADIUS];
        int gindex = block_start + j;

        // Load data into temp (first parallel loop)
